(()=>{"use strict";window.StringUtils={createPacPlugin:e=>({name:"StringUtils",functions:{capitalize:e=>e.charAt(0).toUpperCase()+e.slice(1).toLowerCase(),upper:e=>e.toUpperCase(),lower:e=>e.toLowerCase(),trim:e=>e.trim(),truncate:(e,t,a="…")=>e.length<=t?e:e.slice(0,t-a.length)+a,replace:(e,t,a)=>e.replace(t,a),replaceAll:(e,t,a)=>e.replaceAll(t,a),startsWith:(e,t)=>e.startsWith(t),endsWith:(e,t)=>e.endsWith(t),contains:(e,t)=>e.includes(t),padStart:(e,t,a=" ")=>e.padStart(t,a),padEnd:(e,t,a=" ")=>e.padEnd(t,a),repeat:(e,t)=>e.repeat(t),length:e=>e.length,slug:e=>e.toLowerCase().trim().replace(/[^a-z0-9]+/g,"-").replace(/^-+|-+$/g,"")}})}})();